import fs from 'fs';
import OpenAI from 'openai';

const client = new OpenAI({
  apiKey: 'YOUR_NEOSANTARA_API_KEY',
  baseURL: 'https://api.neosantara.xyz/v1'
});

const transcription = await client.audio.transcriptions.create({
  file: fs.createReadStream('speech.mp3'),
  model: 'whisper-large-v3-turbo',
});
console.log(transcription.text);

import OpenAI from 'openai';

const client = new OpenAI({
  apiKey: 'YOUR_NEOSANTARA_API_KEY',
  baseURL: 'https://api.neosantara.xyz/v1'
});

const response = await client.images.generate({
  model: 'neosantara-gen-2045',
  prompt: 'Pemandangan alam Indonesia yang indah',
  n: 1,
  size: '1024x1024',
});
console.log(response.data[0].url);

import OpenAI from 'openai';

const client = new OpenAI({
  apiKey: 'YOUR_NEOSANTARA_API_KEY',
  baseURL: 'https://api.neosantara.xyz/v1'
});

const response = await client.chat.completions.create({
  model: 'gemini-3-flash',
  messages: [{ role: 'user', content: 'Halo, apa kabar?' }],
});
console.log(response.choices[0].message.content);

import OpenAI from 'openai';

const client = new OpenAI({
  apiKey: 'YOUR_NEOSANTARA_API_KEY',
  baseURL: 'https://api.neosantara.xyz/v1'
});

const response = await client.responses.create({
  model: 'claude-4.5-sonnet',
  input: 'Halo, apa kabar?',
  instructions: 'Jawab dengan gaya santai.',
  store: true
});
console.log(response.output_text);

import Anthropic from '@anthropic-ai/sdk';

const client = new Anthropic({
  apiKey: 'YOUR_NEOSANTARA_API_KEY',
  baseURL: 'https://api.neosantara.xyz/anthropic'
});

const message = await client.messages.create({
  model: 'archipelago-70b',
  max_tokens: 1024,
  messages: [{ role: 'user', content: 'Halo, apa kabar?' }],
});
console.log(message.content[0].text);

import OpenAI from 'openai';

const client = new OpenAI({
  apiKey: 'YOUR_NEOSANTARA_API_KEY',
  baseURL: 'https://api.neosantara.xyz/v1'
});

const response = await client.embeddings.create({
  model: 'nusa-embedding-0001',
  input: 'Kecerdasan Buatan adalah masa depan.',
});
console.log(response.data[0].embedding);
